def _compute_entropy(self, attn_stack):
    """Average entropy of attention distributions."""
    entropies = []
    for layer in attn_stack:
        for head in layer:
            for row in head:
                row_entropy = entropy(row + 1e-10)
                entropies.append(row_entropy)
    return np.mean(entropies)
